ETCOP_TOOL.JSON_STRUCTURE:
{
  "type": "function",
  "function": {
    "name": "HelloWorldTool",
    "description": "This is the classic HelloWorld tool implementation.",
    "parameters": {
      "type": "object",
      "properties": {"query": {
        "description": "query to look up",
        "title": "Query",
        "type": "string"
      }}
    }
  }
}

{
  "type": "function",
  "function": {
    "name": "CustomHelloWorldMultiArgsTool",
    "description": "This is the CustomHelloWorldMultiArgsTool tool implementation.",
    "parameters": {
      "type": "object",
      "properties": {
        "a": {
          "description": "first number",
          "title": "A",
          "type": "integer"
        },
        "b": {
          "description": "second number",
          "title": "B",
          "type": "integer"
        }
      }
    }
  }
}

{
  "type": "function",
  "function": {
    "name": "SimpleOcrTool",
    "description": "Extracts structured data from images and PDF documents using direct vision AI APIs. Sends files natively without image conversion. Best for: invoices, receipts, forms, contracts, and any structured document. Supports structured output schemas from tools\/schemas\/ directory. Supports: JPEG, PNG, WebP, GIF, and PDF files.",
    "parameters": {
      "type": "object",
      "properties": {
        "path": {
          "description": "Absolute or relative path to the image or PDF file to be processed. The file must exist in the local file system.",
          "title": "Path",
          "type": "string"
        },
        "question": {
          "description": "Specific instructions describing what information to extract from the document. Be precise about the data fields needed.",
          "title": "Question",
          "type": "string"
        },
        "structured_output": {
          "anyOf": [
            {"type": "string"},
            {"type": "null"}
          ],
          "default": null,
          "description": "Schema name for structured output (e.g., 'Invoice'). Schemas are loaded from tools\/schemas\/. Leave None for unstructured JSON extraction.",
          "title": "Structured Output"
        },
        "structured_output_schema": {
          "anyOf": [
            {
              "additionalProperties": true,
              "type": "object"
            },
            {"type": "null"}
          ],
          "default": null,
          "description": "Literal JSON Schema dict to use as the structured output format. When provided, takes precedence over `structured_output`. Lets callers define the extraction shape inline instead of shipping a Pydantic class in tools\/schemas\/.",
          "title": "Structured Output Schema"
        }
      }
    }
  }
}
